request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Find tasks NOT reachable from the start event
# First get all tasks, then filter out those reachable from start
SELECT ?task ?taskName WHERE {
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_57deb9e0_f5ba_4380_a35e_0656d288167a> .
  ?task a bboExt:ChoreographyTask .
  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER NOT EXISTS {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-F53DDAEA-5C69-42E2-B442-4626A6064827> ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 50
